# -*- coding: utf-8 -*-
# Writes the complete tarot-cards.json from compact data

import json, os

os.chdir(os.path.dirname(os.path.abspath(__file__)))

def card(id, name, cn, kws, meaning, love, career, health, spirituality, hashtag_suffix=""):
    suffix = hashtag_suffix or name.replace(" ", "").replace("of", "")
    return {
        "id": id, "name": name, "nameCn": cn, "keywords": kws,
        "meaning": meaning, "love": love, "career": career, "health": health, "spirituality": spirituality,
        "affirmation": f"I connect with the energy of {name} and embrace its gift.",
        "actionSteps": [
            f"Today, contemplate the deeper meaning of {name}",
            "Take one action aligned with this card's energy",
            "Journal your feelings and insights"
        ],
        "shareText": f"Daily Tarot | {name} ({cn}) has appeared! {kws[0]} energy shines upon you!",
        "shareHashtags": f"#Tarot #{suffix} #WishingMoon"
    }

